// Worked focus: httpsts-liveness-readiness-startup — Separate liveness, readiness, startup, dependency state, saturation, draining, and management endpoint protection without causing probe storms.
// Evidence: httpsts-worked-http-server-ts-observability-health-3
// Competency: httpsts-worked-http-server-ts-observability-health-3.
// Case 5798: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_observability_health_3(routeKnown: boolean, status: number, queueDepth: number, queueCapacity: number): { spanName: string; error: boolean; ready: boolean } {
  const spanName = routeKnown ? "GET /incidents/{id}" : "HTTP request";
  const error = status >= 500;
  const ready = queueCapacity > 0 && queueDepth >= 0 && queueDepth < queueCapacity;
  return { spanName, error, ready };
}

